  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 27, 'אני מחזק את היכולת לפתח משחקים עם סיפור ועומק רגשי.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 28, 'אני מלווה תהליכי פיתוח משחקים אינטראקטיביים למכשירים ניידים.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 29, 'אני מסייע בהקניית מיומנויות סטרימינג וקידום משחקים ברשת.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 30, 'אני מלווה תהליכי יצירת משחקים שיתופיים ומחברים בין קהילות.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 31, 'אני מחזק את היכולת לשלב משחקיות ואסתטיקה בצורה חכמה ומושכת.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 32, 'אני מלווה תהליכי פיתוח ממשק משתמש נגיש וברור.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 33, 'אני מסייע ביצירת משחקים שמאתגרים חשיבה ויכולות קוגניטיביות.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 34, 'אני מחזק את היכולת לשפר ביצועים ותגובה במשחק.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 35, 'אני מלווה תהליכי עבודה עם כלי פיתוח גרפיים וטכנולוגיים מתקדמים.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 36, 'אני מסייע ביצירת משחקים שמעוררים השראה ויצירתיות.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 37, 'אני מחזק את היכולת לפתח פתרונות טכנולוגיים לבעיות משחק מורכבות.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 38, 'אני מלווה תהליכי פיתוח משחקים חינוכיים והעשרה.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 39, 'אני מסייע ביצירת חוויות משחק שמותאמות לכל סוגי השחקנים.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 40, 'אני מלווה תהליכי פיתוח חוויות אינטראקטיביות חדשניות.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 41, 'אני מחזק את היכולת לשלב סיפור, גרפיקה, מוזיקה וטכנולוגיה באופן הרמוני.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 42, 'אני מלווה תהליכי פיתוח משחקים עם דגש על קיימות ותרומה חברתית.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 43, 'אני מסייע ביצירת חוויות מרתקות שמחזקות מעורבות וקשר רגשי לשחקן.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 44, 'אני מלווה תהליכי יצירת משחקים שמחברים אנשים וקהילות.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 45, 'אני מחזק את היכולת להשתמש בכלים מתקדמים לפיתוח ואנימציה.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 46, 'אני מלווה תהליכי פיתוח חוויות משחק חדשניות בעולם הדיגיטלי.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 47, 'אני מסייע בהעצמת כישורים טכנולוגיים ואמנותיים בקרב צוותים.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 48, 'אני מחזק את היכולת ליצור משחקים עם ערכים חינוכיים וחברתיים.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 49, 'אני מלווה תהליכי פיתוח משחקים שמותאמים לעולם המסחרי והשיווקי.'),
  (30, 'משחקי מחשב וגיימינג', 'פיתוח משחקים, סטרימינג, עיצוב חוויית משתמש', 50, 'אני מסייע להשפיע על תחום המשחקים הדיגיטליים בצורה משמעותית ומועילה.');
